  <text x="35" y="278" fill="#c4b5fd" font-family="sans-serif" font-size="12">&#8594; No se anunció fondo nuevo, monto ni cambio regulatorio inmediato</text>
  <rect x="20" y="300" width="660" height="80" rx="8" fill="#18181b" stroke="#3f3f46"/>
