  <text x="35" y="222" fill="#fcd34d" font-family="sans-serif" font-size="12">&#8594; Thời điểm trình Quốc hội và thực thi vẫn chưa xác định</text>
  <rect x="20" y="240" width="660" height="46" rx="6" fill="#1e1633" stroke="#7c3aed"/>
